BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?owner ?ownerName ?elem ?elemName WHERE {
  ?elem vocab:NamedElement_name "Pupil Alignment Error Budget" .
  ?elem rdf:type vocab:package .
  ?elem vocab:Element_owner ?owner .
  OPTIONAL { ?owner vocab:NamedElement_name ?ownerName }
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
}
LIMIT 25

